    'cookiesPage.subtitleBlock5-p': { es: 'Puedes permitir, bloquear o eliminar las cookies desde la configuración de tu navegador. Consulta la ayuda de cada navegador en estos enlaces:', en: 'You can allow, block, or delete cookies from your browser settings. Consult the help section of each browser at the following links:' },
    'cookiesPage.subtitleBlock5-p1': { es: 'Si prefieres evitar el uso de cookies no esenciales, puedes rechazarlas o configurar tus preferencias desde el panel de consentimiento. Si ya las has aceptado, no volveremos a preguntarte a menos que borres las cookies o actualices tus preferencias.', en: 'If you prefer to avoid the use of non-essential cookies, you can reject them or configure your preferences from the consent panel. If you have already accepted them, we will not ask you again unless you delete the cookies or update your preferences.' },
    'cookiesPage.subtitleBlock6':   { es: 'Tabla de cookies utilizadas',     en: 'Table of cookies used' },
